+        let mut pool = SymbolPool::new(config);
+        pool.warm(4);
+        assert_eq!(pool.free_count(), 4);
+        let _ = pool.allocate().expect("allocation");
+        pool.shrink_to_fit();
+        assert!(pool.free_count() <= 1);
